// Pull the sender phone and the message text out of the WhatsApp webhook,
// then work out what the officer is asking for.
const j = $input.first().json;
let msg = (j.messages && j.messages[0])
  || (j.entry && j.entry[0] && j.entry[0].changes && j.entry[0].changes[0] && j.entry[0].changes[0].value && j.entry[0].changes[0].value.messages && j.entry[0].changes[0].value.messages[0])
  || j;
const from = msg.from || j.from || (j.contacts && j.contacts[0] && j.contacts[0].wa_id) || '';
const textRaw = (msg.text && msg.text.body) || msg.body || j.text || '';
const text = String(textRaw).trim();
const low = text.toLowerCase();
let intent = 'brief';
if (/cost|budget|money|mari|price/.test(low)) intent = 'cost';
else if (/deadline|when|nguva|date|time/.test(low)) intent = 'deadline';
else if (/data|verify|source|proof|ongorora|check|feed/.test(low)) intent = 'data';
else if (/^(hi|hie|hello|help|start|menu|list|mhoro)\b/.test(low) || low.length === 0) intent = 'help';
return [{ json: { from, text, low, intent, hasText: text.length > 0 } }];

// Turn the officer's question + the LIVE Hozi data into a WhatsApp reply.
const req = $('Parse Message').item.json;
const projRaw = $('Fetch Projections').item.json.data || '';
const briefRaw = $('Fetch Briefs').item.json.data || '';
const APP = 'https://hozi-xi.vercel.app/';
const reply = (body) => [{ json: { to: req.from, body } }];

function unwrap(raw, marker){ const i = raw.indexOf(marker); if(i<0) throw new Error('no marker'); let s = raw.slice(i+marker.length).trim(); s = s.replace(/;+\s*$/, ''); return JSON.parse(s); }
let proj=null, briefs=null;
try { proj = unwrap(projRaw, 'window.HOZI='); } catch(e){}
try { briefs = unwrap(briefRaw, 'window.HOZI_BRIEFS='); } catch(e){}
if(!proj){ return reply('🌾 Hozi is briefly unavailable — please try again shortly.'); }

const districts = proj.districts || [];
const watch = proj.watch || [];
let picked = null;
for(const d of districts){ if(req.low.includes(d.district.toLowerCase())){ picked = d; break; } }

const MON = {'05':'May','06':'June','07':'July','08':'August','09':'September'};
const LAST = {'01':'31','02':'28','03':'31','04':'30','05':'31','06':'30','07':'31','08':'31','09':'30','10':'31','11':'30','12':'31'};
function firstHigh(tl){ for(const p of tl){ if(p.risk>=66) return p.m; } return null; }
function priorEnd(m){ if(!m) return null; let a=m.split('-'); let i=+a[1]-1, yy=+a[0]; if(i<1){i=12;yy--;} const k=String(i).padStart(2,'0'); return `${LAST[k]} ${MON[k]||k} ${yy}`; }

if(req.intent==='help' || !picked){
  const top = watch.slice(0,6).map(w=>`• ${w.district} — ${Math.round(w.projected_sep)} by Sep`).join('\n');
  return reply(`🌾 *Hozi — Food Security*\nText me a *district name* for its early-warning brief.\n\nHighest risk now:\n${top}\n\nThen reply *DEADLINE*, *DATA* or *COST*.\n_Simulation of the pilot officer channel._`);
}

const name = picked.district;
const sep = picked.projected_sep != null ? picked.projected_sep : (picked.forecast ? picked.forecast['2026-09'].risk : null);
const obs = picked.timeline.filter(p=>!p.proj);
const cur = obs.length ? obs[obs.length-1].risk : null;
const band = sep>=66 ? 'HIGH' : (sep>=45 ? 'MEDIUM' : 'LOW');
const fh = firstHigh(picked.timeline);
const deadline = priorEnd(fh);
const dr = picked.latest_drivers || {};
const link = `${APP}?district=${encodeURIComponent(name)}`;
const eb = (briefs && briefs[name] && briefs[name].en) ? briefs[name].en : null;

if(req.intent==='deadline'){
  if(!fh) return reply(`⏰ *${name}* stays below the HIGH threshold (66) on the current forecast — no hard deadline yet. Keep monitoring.\n📍 ${link}`);
  return reply(`⏰ *Decide before ${deadline} — ${name}*\nRisk crosses into *HIGH* in ${MON[fh.split('-')[1]]} (${picked.timeline.find(p=>p.m===fh).risk}).\nTransfers and grain take 25–60 days to arrive, so the decision must come first. Miss it and help lands after families have already sold assets and pulled children from school.\n📍 ${link}`);
}
if(req.intent==='data'){
  const m = eb && /(\d+)%\s+of[^.]*Phase 3\+/.exec(eb.note);
  const ipcLine = m ? `• ZimVAC/IPC label: ${m[1]}% Phase 3+ (Oct 2020) ✓` : `• ZimVAC/IPC label: — (urban, no rural count)`;
  return reply(`📡 *Live data check — ${name}*\n• CHIRPS rainfall: ${dr.rainfall_mm} mm (Jun) ✓\n• NASA/Copernicus NDVI: ${dr.ndvi} ✓\n• Agritex input access: ${dr.inputs}/100 ✓\n${ipcLine}\n• Hozi model risk (Sep): ${sep} · ${band} ✓\n\n_Every reading is read-only from its source. Hozi computes the risk — it never edits the data._\n📍 ${link}`);
}
if(req.intent==='cost'){
  const red = picked.support ? picked.support.reduction : null;
  const sup = picked.support ? picked.support.supported_sep : null;
  return reply(`💵 *Cost & benefit — ${name}*\nThe modelled support package cuts September risk *${sep} → ${sup}* (−${red} points).\nPlanning rates: cash ~$10–13/person/month; grain ~$12/person for the lean season.\nFull IPC-caseload budget loads from the pilot data feed.\n📍 ${link}`);
}
// default → brief
let bullets = '';
if(eb && eb.bullets){ bullets = eb.bullets.slice(0,5).map((b,i)=>`${i+1}. *${b.dept}* — ${String(b.action).split('. ')[0].replace(/\.$/,'')}.`).join('\n'); }
const dl = fh ? `\n🗓️ *Decide before ${deadline}* (enters HIGH in ${MON[fh.split('-')[1]]}).` : '';
return reply(`⚠️ *Hozi Alert — ${name}* (${picked.province})\nFood-security risk: *${band} — ${sep} by September* (now ${cur}).${dl}\n\n*Recommended early actions:*\n${bullets}\n\n📊 Model + IPC cross-check.  📡 Source: Hozi engine (read-only).\n📍 Live map: ${link}\n\n_Reply DEADLINE, DATA or COST. Simulation of the pilot officer channel._`);
